import React, { useState, useEffect } from 'react';
import axios from 'axios';

const API_BASE_URL = 'http://localhost:8000/api/v1/emissions';

function AIModelEmissions() {
  const [emissions, setEmissions] = useState(null);
  const [comparison, setComparison] = useState(null);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [selectedModel, setSelectedModel] = useState(null);

  useEffect(() => {
    fetchData();
    // Refresh every 5 seconds
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  const fetchData = async () => {
    try {
      const [emissionsRes, comparisonRes, statsRes] = await Promise.all([
        axios.get(`${API_BASE_URL}/ai-models/all`),
        axios.get(`${API_BASE_URL}/ai-models/comparison/all`),
        axios.get(`${API_BASE_URL}/ai-models/statistics/overview`)
      ]);

      setEmissions(emissionsRes.data.data);
      setComparison(comparisonRes.data.data);
      setStats(statsRes.data.data);
      setLoading(false);
      setError(null);
    } catch (err) {
      console.error('Error fetching AI emissions data:', err);
      setError(err.message);
      setLoading(false);
    }
  };

  const formatNumber = (value, decimals = 2) => {
    if (value === null || value === undefined || isNaN(value)) return '0.00';
    return parseFloat(value).toFixed(decimals);
  };

  const StatCard = ({ icon, label, value, unit, color, delay }) => (
    <div
      className="glass-card fade-in"
      style={{
        padding: '24px',
        borderLeft: `4px solid ${color}`,
        animationDelay: `${delay}ms`
      }}
    >
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: '12px' }}>
        <span style={{ fontSize: '1.5rem', marginRight: '12px' }}>{icon}</span>
        <p style={{ margin: 0, color: '#a0a0b8', fontSize: '0.9rem', fontWeight: 500 }}>
          {label}
        </p>
      </div>
      <p style={{
        margin: 0,
        fontSize: '2rem',
        fontWeight: 700,
        color: color,
        lineHeight: 1.2
      }}>
        {value}
        {unit && <span style={{ fontSize: '1rem', opacity: 0.8, marginLeft: '4px' }}>{unit}</span>}
      </p>
    </div>
  );

  const ModelCard = ({ model }) => (
    <div
      className="glass-card"
      onClick={() => setSelectedModel(selectedModel === model.model_name ? null : model.model_name)}
      style={{
        padding: '20px',
        cursor: 'pointer',
        borderLeft: '4px solid #4facfe',
        transition: 'all 0.3s ease',
        backgroundColor: selectedModel === model.model_name ? 'rgba(79, 172, 254, 0.1)' : 'transparent'
      }}
    >
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start' }}>
        <div>
          <h4 style={{ margin: '0 0 8px 0', color: '#ffffff', fontSize: '1.1rem' }}>
            {model.model_name}
          </h4>
          <p style={{ margin: '4px 0', color: '#a0a0b8', fontSize: '0.85rem' }}>
            Type: {model.model_type}
          </p>
          <p style={{ margin: '4px 0', color: '#a0a0b8', fontSize: '0.85rem' }}>
            Hardware: {model.hardware}
          </p>
        </div>
        <div style={{ textAlign: 'right' }}>
          <p style={{ margin: 0, fontSize: '1.5rem', color: '#00f2fe', fontWeight: 700 }}>
            {formatNumber(model.co2_kg, 2)}
          </p>
          <p style={{ margin: '4px 0 0 0', color: '#a0a0b8', fontSize: '0.85rem' }}>
            kg CO₂
          </p>
        </div>
      </div>

      {selectedModel === model.model_name && (
        <div style={{ marginTop: '16px', paddingTop: '16px', borderTop: '1px solid rgba(255, 255, 255, 0.1)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px', fontSize: '0.85rem' }}>
            <div>
              <p style={{ margin: 0, color: '#a0a0b8' }}>Energy Used</p>
              <p style={{ margin: '4px 0 0 0', color: '#4facfe', fontWeight: 600 }}>
                {formatNumber(model.energy_kwh, 3)} kWh
              </p>
            </div>
            <div>
              <p style={{ margin: 0, color: '#a0a0b8' }}>Runtime</p>
              <p style={{ margin: '4px 0 0 0', color: '#4facfe', fontWeight: 600 }}>
                {formatNumber(model.runtime_minutes, 1)} min
              </p>
            </div>
            <div>
              <p style={{ margin: 0, color: '#a0a0b8' }}>Efficiency</p>
              <p style={{ margin: '4px 0 0 0', color: '#4facfe', fontWeight: 600 }}>
                {formatNumber(model.efficiency_g_per_minute, 2)} g/min
              </p>
            </div>
            <div>
              <p style={{ margin: 0, color: '#a0a0b8' }}>Type</p>
              <p style={{ margin: '4px 0 0 0', color: '#4facfe', fontWeight: 600 }}>
                {model.model_type}
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  if (loading) {
    return (
      <div style={{ marginBottom: '48px' }}>
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: '32px' }}>
          <div style={{
            width: '4px',
            height: '32px',
            background: 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)',
            borderRadius: '2px',
            marginRight: '16px'
          }}></div>
          <h2 style={{ fontSize: '1.75rem', fontWeight: 700, margin: 0, color: '#ffffff' }}>
            AI Model CO₂ Emissions
          </h2>
        </div>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: '24px'
        }}>
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="shimmer glass-card" style={{ height: '120px' }}></div>
          ))}
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ marginBottom: '48px' }}>
        <div style={{ display: 'flex', alignItems: 'center', marginBottom: '32px' }}>
          <div style={{
            width: '4px',
            height: '32px',
            background: 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)',
            borderRadius: '2px',
            marginRight: '16px'
          }}></div>
          <h2 style={{ fontSize: '1.75rem', fontWeight: 700, margin: 0, color: '#ffffff' }}>
            AI Model CO₂ Emissions
          </h2>
        </div>
        <div className="glass-card" style={{ padding: '32px', textAlign: 'center' }}>
          <span style={{ fontSize: '3rem' }}>⚠️</span>
          <h3 style={{ color: '#ffffff', marginTop: '16px' }}>Unable to Load AI Emissions Data</h3>
          <p style={{ color: '#a0a0b8' }}>
            {error || 'Please ensure the backend is running and AI models have been executed.'}
          </p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ marginBottom: '48px' }}>
      <div style={{ display: 'flex', alignItems: 'center', marginBottom: '32px' }}>
        <div style={{
          width: '4px',
          height: '32px',
          background: 'linear-gradient(135deg, #00f2fe 0%, #4facfe 100%)',
          borderRadius: '2px',
          marginRight: '16px'
        }}></div>
        <h2 style={{ fontSize: '1.75rem', fontWeight: 700, margin: 0, color: '#ffffff' }}>
          AI Model CO₂ Emissions
        </h2>
      </div>

      {stats && (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
          gap: '24px',
          marginBottom: '32px'
        }}>
          <StatCard
            icon="🤖"
            label="Models Tracked"
            value={stats.total_models || 0}
            color="#4facfe"
            delay={0}
          />
          <StatCard
            icon="🌍"
            label="Total CO₂"
            value={formatNumber(stats.total_co2_kg, 2)}
            unit="kg"
            color="#00f2fe"
            delay={100}
          />
          <StatCard
            icon="⚡"
            label="Total Energy"
            value={formatNumber(stats.total_energy_kwh, 2)}
            unit="kWh"
            color="#fee140"
            delay={200}
          />
          <StatCard
            icon="📊"
            label="Models Run"
            value={emissions ? emissions.length : 0}
            color="#667eea"
            delay={300}
          />
        </div>
      )}

      {comparison && comparison.models && comparison.models.length > 0 && (
        <div style={{ marginBottom: '32px' }}>
          <h3 style={{ fontSize: '1.2rem', color: '#ffffff', marginBottom: '16px' }}>
            Model Comparison
          </h3>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
            gap: '16px'
          }}>
            {comparison.models.map((model, idx) => (
              <ModelCard key={idx} model={model} />
            ))}
          </div>
        </div>
      )}

      {comparison && (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(250px, 1fr))',
          gap: '16px',
          marginTop: '24px'
        }}>
          <div className="glass-card" style={{ padding: '20px', textAlign: 'center' }}>
            <p style={{ margin: 0, color: '#a0a0b8', fontSize: '0.9rem' }}>Highest CO₂ Emissions</p>
            <p style={{ margin: '8px 0 0 0', fontSize: '1.3rem', color: '#ff6b6b', fontWeight: 700 }}>
              {comparison.highest_co2 || 'N/A'}
            </p>
          </div>
          <div className="glass-card" style={{ padding: '20px', textAlign: 'center' }}>
            <p style={{ margin: 0, color: '#a0a0b8', fontSize: '0.9rem' }}>Lowest CO₂ Emissions</p>
            <p style={{ margin: '8px 0 0 0', fontSize: '1.3rem', color: '#51cf66', fontWeight: 700 }}>
              {comparison.lowest_co2 || 'N/A'}
            </p>
          </div>
        </div>
      )}
    </div>
  );
}

export default AIModelEmissions;
